import React, {createContext, type FC, type PropsWithChildren, useContext, useEffect, useState} from 'react';
import {PrimeReactContext} from "primereact/api";
import type {IThemeContextProps, IThemeContextValues} from "@lmb-it/kitsconcerto-types";

// import 'primeflex/primeflex.css'
// import 'primeflex/themes/primeone-light.css'

const ThemeContext = createContext<IThemeContextValues>({} as IThemeContextValues);

const ThemeContextProvider: FC<PropsWithChildren<IThemeContextProps>> = ({children, theme}) => {
    const {changeTheme} = useContext(PrimeReactContext);

    const [selectedTheme, setSelectedTheme] = useState<'light' | 'dark'>('light');

    const doc = () => document.getElementById('app-theme');

    useEffect(() => {
        theme && setSelectedTheme(theme)
    }, [theme]);

    useEffect(() => {
        const m = doc()
        if (m) {
            const href = m.getAttribute('href')
            const t = href?.includes('dark') ? 'dark' : 'light';
            setSelectedTheme(t)
        }
    }, [])
    const switchTheme = (themeFile: string | undefined = undefined) => {
        const m = doc()

        let getCurrentFileName = 'light'

        const newTheme = selectedTheme === 'dark' ? 'light' : 'dark';
        if (m) {
            getCurrentFileName = m.getAttribute('href') ?? 'light'
        }
        let newFileName: string;

        if (!themeFile) {

            let toArray = getCurrentFileName.split(selectedTheme)

            newFileName = toArray.join(newTheme);

        } else {
            newFileName = `/node_modules/primereact/resources/themes/${themeFile}/theme.css`;
        }

        if (changeTheme) {
            changeTheme(getCurrentFileName, newFileName, 'app-theme', () =>
                setSelectedTheme(newTheme)
            );
        }

    };

    return (
        <ThemeContext.Provider value={{
            switchTheme,
            theme: selectedTheme
        }}>
            {children}
        </ThemeContext.Provider>
    );
};

export default ThemeContextProvider;

export const useTheme = () => useContext(ThemeContext);

export {KitsThemeProvider, useKitsTheme} from './KitsThemeProvider.web';
export {extendTheme, deepMerge} from './utils';
